-template<class ActionSpec>
-void SimpleActionClient<ActionSpec>::handleFeedback(GoalHandleT gh, const FeedbackConstPtr& feedback)
-{
-  if (gh_ != gh)
-    ROS_ERROR("Got a callback on a goalHandle that we're not tracking.  \
