+#ifndef ACTIONLIB_CLIENT_TERMINAL_STATE_H_
+#define ACTIONLIB_CLIENT_TERMINAL_STATE_H_
+
+namespace actionlib
+{
+
+class TerminalState
+{
+public:
+  enum StateEnum
+  {
+    RECALLED,
+    REJECTED,
+    PREEMPTED,
+    ABORTED,
+    SUCCEEDED,
+    LOST
+  } ;
+
+  TerminalState(const StateEnum& state) : state_(state) { }
+
+  inline bool operator==(const TerminalState& rhs) const
+  {
+    return (state_ == rhs.state_) ;
+  }
+
+  inline bool operator==(const TerminalState::StateEnum& rhs) const
+  {
+    return (state_ == rhs);
+  }
+
+  inline bool operator!=(const TerminalState::StateEnum& rhs) const
+  {
+    return !(*this == rhs);
+  }
+
+  inline bool operator!=(const TerminalState& rhs) const
+  {
+    return !(*this == rhs);
+  }
+
+  std::string toString() const
+  {
+    switch(state_)
+    {
+      case RECALLED:
+        return "RECALLED";
+      case REJECTED:
+        return "REJECTED";
+      case PREEMPTED:
+        return "PREEMPTED";
+      case ABORTED:
+        return "ABORTED";
+      case SUCCEEDED:
+        return "SUCCEEDED";
+      case LOST:
+        return "LOST";
+
+      default:
+        ROS_ERROR("BUG: Unhandled TerminalState: %u", state_);
+        break;
+    }
+    return "BUG-UNKNOWN";
+  }
+
+  StateEnum state_;
+private:
+  TerminalState();
+
+} ;
+
+}
+
+#endif

